import React, { useState, useEffect } from 'react';
import { TaskItem } from './TaskItem';

export function TaskList({ tasks, onTasksUpdated, filter = 'all' }) {
  const [filteredTasks, setFilteredTasks] = useState(tasks);
  const [sortBy, setSortBy] = useState('createdAt');

  useEffect(() => {
    let filtered = [...tasks];

    // Apply status filter
    if (filter === 'active') {
      filtered = filtered.filter(t => t.status === 'PENDING');
    } else if (filter === 'completed') {
      filtered = filtered.filter(t => t.status === 'COMPLETED');
    }

    // Apply sorting
    filtered.sort((a, b) => {
      if (sortBy === 'priority') {
        const priorityOrder = { HIGH: 0, MEDIUM: 1, LOW: 2 };
        return priorityOrder[a.priority] - priorityOrder[b.priority];
      } else if (sortBy === 'dueDate') {
        if (!a.dueDate) return 1;
        if (!b.dueDate) return -1;
        return new Date(a.dueDate) - new Date(b.dueDate);
      } else {
        return new Date(b.createdAt) - new Date(a.createdAt);
      }
    });

    setFilteredTasks(filtered);
  }, [tasks, filter, sortBy]);

  const handleTaskUpdated = (updatedTask) => {
    if (updatedTask === null) {
      // Task was deleted
      const updatedTasks = tasks.filter(t => t !== updatedTask);
      if (onTasksUpdated) onTasksUpdated(updatedTasks);
    } else {
      // Task was updated
      const updatedTasks = tasks.map(t => t.id === updatedTask.id ? updatedTask : t);
      if (onTasksUpdated) onTasksUpdated(updatedTasks);
    }
  };

  const stats = {
    total: tasks.length,
    completed: tasks.filter(t => t.status === 'COMPLETED').length,
    active: tasks.filter(t => t.status === 'PENDING').length,
    high: tasks.filter(t => t.priority === 'HIGH').length,
  };

  return (
    <div>
      {/* Stats Bar */}
      <div className="grid grid-cols-4 gap-4 mb-6">
        <div className="card p-4 text-center hover:shadow-lg transition-shadow">
          <div className="text-3xl font-bold text-blue-600">{stats.total}</div>
          <div className="text-sm text-gray-600">Total Tasks</div>
        </div>
        <div className="card p-4 text-center hover:shadow-lg transition-shadow">
          <div className="text-3xl font-bold text-green-600">{stats.active}</div>
          <div className="text-sm text-gray-600">Active</div>
        </div>
        <div className="card p-4 text-center hover:shadow-lg transition-shadow">
          <div className="text-3xl font-bold text-purple-600">{stats.completed}</div>
          <div className="text-sm text-gray-600">Completed</div>
        </div>
        <div className="card p-4 text-center hover:shadow-lg transition-shadow">
          <div className="text-3xl font-bold text-red-600">{stats.high}</div>
          <div className="text-sm text-gray-600">High Priority</div>
        </div>
      </div>

      {/* Sorting Controls */}
      <div className="mb-6 flex gap-3">
        <label className="text-sm font-medium text-gray-700 flex items-center">
          Sort by:
          <select
            value={sortBy}
            onChange={(e) => setSortBy(e.target.value)}
            className="ml-2 px-3 py-1 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="createdAt">📅 Newest First</option>
            <option value="priority">🔴 Priority</option>
            <option value="dueDate">⏰ Due Date</option>
          </select>
        </label>
      </div>

      {/* Tasks List */}
      {filteredTasks.length === 0 ? (
        <div className="card p-12 text-center">
          <div className="text-5xl mb-4">🎉</div>
          <h3 className="text-xl font-semibold text-gray-700 mb-2">
            {filter === 'completed' ? 'No completed tasks yet!' : 'No tasks to show!'}
          </h3>
          <p className="text-gray-500">
            {filter === 'all' && 'Create a new task to get started.'}
            {filter === 'active' && 'All tasks are completed! Great job! 🚀'}
            {filter === 'completed' && 'Complete some tasks to see them here.'}
          </p>
        </div>
      ) : (
        <div className="animate-fade-in">
          {filteredTasks.map((task) => (
            <TaskItem
              key={task.id}
              task={task}
              onTaskUpdated={handleTaskUpdated}
            />
          ))}
        </div>
      )}
    </div>
  );
}
